public class ObserverPattern {
    interface Observer { void update(String event); }
    static class EventBus {
        java.util.List<Observer> obs = new java.util.ArrayList<>();
        void subscribe(Observer o) { obs.add(o); }
        void publish(String event) { for (Observer o : obs) o.update(event); }
    }
    public static void main(String[] args) {
        EventBus bus = new EventBus();
        bus.subscribe(e -> System.out.println("A:" + e));
        bus.subscribe(e -> System.out.println("B:" + e));
        bus.publish("click");
        bus.publish("hover");
    }
}
